#include<bits/stdc++.h>
using namespace std;
const int MAXN=4e1+5;
int n,l,r,ans,a[MAXN],w[MAXN];
void dfs(int u){
    int sum=0;for(int i=1;i<=u-1;++i)sum+=w[i]*a[i];
    if(sum>r)return;if(u==n+1){if(sum>=l)++ans;return;}
	for(int i=0;i<=1;++i){a[u]=i;dfs(u+1);}
}
int main(void){
	scanf("%d%d%d",&n,&l,&r);
    for(int i=1;i<=n;++i)scanf("%d",w+i);
    dfs(1);printf("%d",ans);
    return false;
}
